const bcrypt = require('bcryptjs');
const jwt = require('jsonwebtoken');
const { validationResult } = require('express-validator');
const { createUser, findUserByUsername } = require('../models/user');

const generateTokens = (user) => {
  const accessToken = jwt.sign({ id: user.id }, process.env.JWT_SECRET, {
    expiresIn: process.env.JWT_ACCESS_EXPIRATION_MINUTES
  });
  const refreshToken = jwt.sign({ id: user.id }, process.env.JWT_SECRET, {
    expiresIn: process.env.JWT_REFRESH_EXPIRATION_DAYS * 24 * 60 * 60
  });
  return { accessToken, refreshToken };
};

const register = async (req, res) => {
  const errors = validationResult(req);
  if (!errors.isEmpty()) {
    return res.status(400).json({ errors: errors.array() });
  }

  const { username, password } = req.body;
  try {
    const hashedPassword = await bcrypt.hash(password, 10);
    const result = await createUser(username, hashedPassword);
    const user = result.rows[0];
    const tokens = generateTokens(user);
    res.status(201).json({ user, tokens });
  } catch (error) {
    res.status(500).json({ message: 'Server error' });
  }
};

const login = async (req, res) => {
  const errors = validationResult(req);
  if (!errors.isEmpty()) {
    return res.status(400).json({ errors: errors.array() });
  }

  const { username, password } = req.body;
  try {
    const result = await findUserByUsername(username);
    if (result.rowCount === 0) {
      return res.status(401).json({ message: 'User not found' });
    }

    const user = result.rows[0];
    const isPasswordValid = await bcrypt.compare(password, user.password);
    if (!isPasswordValid) {
      return res.status(401).json({ message: 'Invalid password' });
    }

    const tokens = generateTokens(user);
    res.json({ user, tokens });
  } catch (error) {
    res.status(500).json({ message: 'Server error' });
  }
};

const refresh = (req, res) => {
  const refreshToken = req.body.refreshToken;
  if (!refreshToken) {
    return res.status(401).json({ message: 'Refresh token required' });
  }

  jwt.verify(refreshToken, process.env.JWT_SECRET, async (err, user) => {
    if (err) {
      return res.status(401).json({ message: 'Invalid refresh token' });
    }

    try {
      const result = await findUserByUsername(user.username);
      if (result.rowCount === 0) {
        return res.status(401).json({ message: 'User not found' });
      }

      const tokens = generateTokens(result.rows[0]);
      res.json(tokens);
    } catch (error) {
      res.status(500).json({ message: 'Server error' });
    }
  });
};

module.exports = {
  register,
  login,
  refresh
};
```

