package main

import (
	"context"
	"fmt"
	"log"
	"net/http"
	"time"

	"github.com/go-redis/redis/v8"
	"github.com/prometheus/client_golang/prometheus"
	"github.com/prometheus/client_golang/prometheus/promauto"
	"github.com/prometheus/client_golang/prometheus/promhttp"
)

var (
	ctx    = context.Background()
	rdb    *redis.Client
	config = map[string]int{
		"client1": 100, // 100 requests per minute
		"client2": 200, // 200 requests per minute
		// Add more clients as needed
	}

	windowSize = 60 * time.Second

	limitExceeded = promauto.NewCounter(prometheus.CounterOpts{
		Name: "rate_limiter_limit_exceeded",
		Help: "Number of times the rate limit was exceeded",
	})

	requestsProcessed = promauto.NewCounter(prometheus.CounterOpts{
		Name: "rate_limiter_requests_processed",
		Help: "Number of requests processed",
	})

	fallbackUsed = promauto.NewCounter(prometheus.CounterOpts{
		Name: "rate_limiter_fallback_used",
		Help: "Number of times fallback was used",
	})
)

func initRedis() {
	rdb = redis.NewClient(&redis.Options{
		Addr:     "localhost:6379",
		Password: "", // no password set
		DB:       0,  // use default DB
	})
}

func getRateLimitKey(clientID string) string {
	return fmt.Sprintf("rate_limit:%s", clientID)
}

func getRateLimitWindowKey(clientID string) string {
	return fmt.Sprintf("rate_limit_window:%s", clientID)
}

func isRateLimited(clientID string, limit int) (bool, error) {
	key := getRateLimitKey(clientID)
	windowKey := getRateLimitWindowKey(clientID)

	// Get the current timestamp
	now := time.Now().UnixNano()

	// Push the current timestamp to the list
	err := rdb.RPush(ctx, windowKey, now).Err()
	if err != nil {
		return false, err
	}

	// Trim the list to only include timestamps within the window size
	_, err = rdb.LTrim(ctx, windowKey, 0, "-1").Result()
	if err != nil {
		return false, err
	}

	// Get the number of elements in the list
	count, err := rdb.LLen(ctx, windowKey).Result()
	if err != nil {
		return false, err
	}

	// Check if the count exceeds the limit
	if count > int64(limit) {
		return true, nil
	}

	// Set the rate limit key to expire after the window size
	err = rdb.Expire(ctx, windowKey, windowSize).Err()
	if err != nil {
		return false, err
	}

	return false, nil
}

func rateLimiterMiddleware(next http.Handler) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		clientID := r.Header.Get("Client-ID")
		if clientID == "" {
			http.Error(w, "Client-ID header is required", http.StatusBadRequest)
			return
		}

		limit, ok := config[clientID]
		if !ok {
			http.Error(w, "Unknown client ID", http.StatusForbidden)
			return
		}

		var isLimited bool
		var err error

		// Try to check rate limit with Redis
		isLimited, err = isRateLimited(clientID, limit)
		if err != nil {
			// Redis connection failure, use local fallback
			fallbackUsed.Inc()
			isLimited = false
		}

		if isLimited {
			limitExceeded.Inc()
			http.Error(w, "Rate limit exceeded", http.StatusTooManyRequests)
			return
		}

		requestsProcessed.Inc()
		next.ServeHTTP(w, r)
	})
}

func main() {
	initRedis()

	http.Handle("/", rateLimiterMiddleware(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		w.Write([]byte("Hello, Rate Limiter!"))
	})))

	http.Handle("/metrics", promhttp.Handler())

	log.Println("Starting server on :8080")
	log.Fatal(http.ListenAndServe(":8080", nil))
}
```

### Explanation

1. **Redis Initialization**: The `initRedis` function initializes the Redis client.
2. **Rate Limiting Key Functions**: `getRateLimitKey` and `getRateLimitWindowKey` generate the Redis keys for each client.
3. **Rate Limiting Check**: The `isRateLimited` function checks if the client has exceeded the rate limit by pushing the current timestamp to a Redis list and trimming the list to only include timestamps within the window size.
4. **Middleware**: The `rateLimiterMiddleware` function is a middleware that checks the rate limit for each request. If the rate limit is exceeded, it returns a 429 status. If there is a Redis connection failure, it falls back to allowing the request and increments the `fallbackUsed` metric.
5. **Metrics**: The `prometheus` metrics are exposed at the `/metrics` endpoint.
6. **Main Function**: The `main` function sets up the HTTP server with the rate limiter middleware and Prometheus metrics endpoint.

This implementation should meet your requirements for a distributed rate limiter with a sliding window algorithm backed by Redis.

