```go
package main

import (
	"context"
	"fmt"
	"net/http"
	"strconv"
	"time"

	"github.com/go-chi/chi/v5"
	"github.com/go-chi/chi/v5/middleware"
	"github.com/go-redis/redis/v8"
)

const (
	redisKeyPrefix = "rate_limiter:"
	tokensPerMinute = 100
 refillInterval  = time.Second
)

type RateLimiter struct {
	redisClient *redis.Client
	inMemory    map[string]*Bucket
}

type Bucket struct {
	Tokens float64
	Last   time.Time
}

func NewRateLimiter(redisClient *redis.Client) *RateLimiter {
	return &RateLimiter{
		redisClient: redisClient,
		inMemory:    make(map[string]*Bucket),
	}
}

func (rl *RateLimiter) Middleware(next http.Handler) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		ip := r.RemoteAddr
		if err := rl.Limit(ip); err != nil {
			http.Error(w, err.Error(), http.StatusTooManyRequests)
			return
		}
		next.ServeHTTP(w, r)
	})
}

func (rl *RateLimiter) Limit(ip string) error {
	key := redisKeyPrefix + ip
	ctx := context.Background()

	// Try to get the bucket from Redis
	bucket, err := rl.getBucketFromRedis(ctx, key)
	if err != nil {
		// If Redis is down, fall back to in-memory store
		bucket = rl.getBucketFromInMemory(ip)
	}

	// Refill tokens
	now := time.Now()
	if now.Sub(bucket.Last) > refillInterval {
		bucket.Tokens = tokensPerMinute
		bucket.Last = now
	}

	if bucket.Tokens > 0 {
		bucket.Tokens--
		rl.setBucketInRedis(ctx, key, bucket)
		rl.setBucketInMemory(ip, bucket)
		return nil
	}

	return fmt.Errorf("rate limit exceeded")
}

func (rl *RateLimiter) getBucketFromRedis(ctx context.Context, key string) (*Bucket, error) {
	redisBucket, err := rl.redisClient.HMGet(ctx, key, "tokens", "last").Result()
	if err != nil {
		return nil, err
	}

	if redisBucket[0] == nil || redisBucket[1] == nil {
		return &Bucket{Tokens: tokensPerMinute, Last: time.Now()}, nil
	}

	tokens, _ := strconv.ParseFloat(redisBucket[0].(string), 64)
	last, _ := strconv.ParseInt(redisBucket[1].(string), 10, 64)

	return &Bucket{Tokens: tokens, Last: time.Unix(last, 0)}, nil
}

func (rl *RateLimiter) setBucketInRedis(ctx context.Context, key string, bucket *Bucket) error {
	return rl.redisClient.HMSet(ctx, key, "tokens", bucket.Tokens, "last", bucket.Last.Unix()).Err()
}

func (rl *RateLimiter) getBucketFromInMemory(ip string) *Bucket {
	if bucket, ok := rl.inMemory[ip]; ok {
		return bucket
	}
	rl.inMemory[ip] = &Bucket{Tokens: tokensPerMinute, Last: time.Now()}
	return rl.inMemory[ip]
}

func (rl *RateLimiter) setBucketInMemory(ip string, bucket *Bucket) {
	rl.inMemory[ip] = bucket
}

func main() {
	r := chi.NewRouter()
	r.Use(middleware.Logger)
	r.Use(NewRateLimiter(redis.NewClient(&redis.Options{
		Addr: "localhost:6379",
	})).Middleware)

	r.Get("/", func(w http.ResponseWriter, r *http.Request) {
		w.Write([]byte("Hello, world!"))
	})

	http.ListenAndServe(":8080", r)
}
```

